#!/usr/bin/env bun
import { join } from "node:path";
import CODE from "../src/CODE.js";

const toCamel = (code) =>
  code
    .split("-")
    .map((i) => i.charAt(0).toUpperCase() + i.slice(1).toLowerCase())
    .join("");

const dir = import.meta.dirname,
  rs_path = join(dir, "rust/src/code.rs"),
  variants = [];

CODE.forEach((code, idx) => {
  const camel = toCamel(code);
  variants.push('  #[strum(to_string = "' + code + '")]\n  ' + camel + " = " + idx + ",");
});

const lines = [
  "// This file is auto-generated by gen/rs.js, do not edit manually.",
  "",
  "use strum::{AsRefStr, Display, FromStr, IntoStaticStr};",
  "#[derive(",
  "  Debug,",
  "  Clone,",
  "  Copy,",
  "  Hash,",
  "  PartialEq,",
  "  Eq,",
  "  PartialOrd,",
  "  Ord,",
  "  Display,",
  "  IntoStaticStr,",
  "  AsRefStr",
  ")]",
  "#[repr(u16)]",
  "pub enum Code {",
  variants.join("\n"),
  "}",
  "",
  "impl Code {",
  "  pub fn as_str(self) -> &'static str {",
  "    self.into()",
  "  }",
  "}",
  "",
  "impl From<Code> for u16 {",
  "  fn from(code: Code) -> Self {",
  "    code as u16",
  "  }",
  "}",
];

const rs_content = lines.join("\n") + "\n";
await Bun.write(rs_path, rs_content);
console.log(rs_path);
